"use client";

import { Zap, Building2, Sparkles } from "lucide-react";
import { cn } from "@/lib/utils";

type Lang = "en" | "fr";

export type Plan = "free" | "pro" | "enterprise" | "trial";

const T: Record<Lang, Record<Plan, string>> = {
  en: { free: "Free", trial: "Trial", pro: "Pro", enterprise: "Enterprise" },
  fr: { free: "Gratuit", trial: "Essai", pro: "Pro", enterprise: "Enterprise" },
};

interface PlanBadgeProps {
  plan: Plan;
  size?: "sm" | "md" | "lg";
  showIcon?: boolean;
  onClick?: () => void;
  lang?: Lang;
  className?: string;
}

const planConfig: Record<Plan, { icon: React.ElementType; className: string }> = {
  free: {
    icon: Sparkles,
    className: "bg-muted text-muted-foreground border border-border",
  },
  trial: {
    icon: Zap,
    className: "bg-yellow-500/10 text-yellow-400 border border-yellow-500/25",
  },
  pro: {
    icon: Zap,
    className: "bg-primary/15 text-primary border border-primary/30",
  },
  enterprise: {
    icon: Building2,
    className: "bg-[oklch(0.75_0.15_80/15%)] text-[oklch(0.80_0.15_80)] border border-[oklch(0.75_0.15_80/30%)]",
  },
};

const sizeConfig = {
  sm: { badge: "text-xs px-1.5 py-0.5 gap-1", icon: "h-2.5 w-2.5" },
  md: { badge: "text-xs px-2 py-0.5 gap-1.5", icon: "h-3 w-3" },
  lg: { badge: "text-sm px-2.5 py-1 gap-1.5", icon: "h-3.5 w-3.5" },
};

export function PlanBadge({
  plan,
  size = "md",
  showIcon = true,
  onClick,
  lang = "en",
  className,
}: PlanBadgeProps) {
  const config = planConfig[plan];
  const sizes = sizeConfig[size];
  const Icon = config.icon;
  const label = T[lang][plan];
  const Component = onClick ? "button" : "span";

  return (
    <Component
      onClick={onClick}
      className={cn(
        "inline-flex items-center rounded-full font-semibold font-mono transition-opacity",
        sizes.badge,
        config.className,
        onClick && "hover:opacity-80 cursor-pointer",
        className
      )}
    >
      {showIcon && <Icon className={cn(sizes.icon, "flex-shrink-0")} />}
      {label}
    </Component>
  );
}

/* Compound: PlanBadgeWithCTA — badge cliquable avec CTA upgrade */
interface PlanBadgeWithCTAProps extends PlanBadgeProps {
  onUpgrade?: () => void;
  upgradeLabel?: string;
}

export function PlanBadgeWithCTA({
  plan,
  lang = "en",
  onUpgrade,
  upgradeLabel,
  ...props
}: PlanBadgeWithCTAProps) {
  const defaultLabel = lang === "fr" ? "Passer au Pro" : "Upgrade to Pro";
  const label = upgradeLabel ?? defaultLabel;

  if (plan === "free" || plan === "trial") {
    return (
      <button onClick={onUpgrade} className="group flex items-center gap-1.5" title={label}>
        <PlanBadge plan={plan} {...props} />
        <span className="text-xs text-muted-foreground group-hover:text-primary transition-colors hidden sm:inline">
          → {label}
        </span>
      </button>
    );
  }

  return <PlanBadge plan={plan} {...props} />;
}
